{"name":"CloseDoorCheckLightLowerBrightness","cron":"","period":0,"code":"wait until ((#Clock).Clock_Hour == 0)
(#Door).Door_Close()
delay(1 HOUR)
do while ((#Clock).Clock_Hour < 6)
    curr = (#LightSensor).LightSensor_Brightness
    if (curr > 30) {
        (#Light).Light_MoveToBrightness(10, 0)
    }
    delay(1 HOUR)
end do"}

{"name":"AnnounceSmokeAndEmailWarning","cron":"","period":0,"code":"wait until ((#SmokeDetector).SmokeDetector_Smoke == true)
(#Speaker).Speaker_Speak("Smoke detected!")
repeat every 5 MIN {
    (#EmailProvider).EmailProvider_SendMail("test@example.com", "Fire Warning", "A fire has occurred. Please evacuate.")
}"}

{"name":"TurnOnEntranceLightFor3Seconds","cron":"","period":100,"code":"prev := (#Entrance #MotionSensor).MotionSensor_Motion
curr = (#Entrance #MotionSensor).MotionSensor_Motion
if (prev == false and curr == true) {
    (#Entrance #Light).LevelControl_MoveToLevel(100, 0)
    delay(3 SEC)
    (#Entrance #Light).Switch_Off()
}
prev = curr"}

{"name":"SetLabDehumidifierModeBasedOnHumidity","cron":"","period":0,"code":"while true {
    current_humidity = (#ServerRack #Humid).HumiditySensor_Humidity
    if (current_humidity > 70) {
        (#Lab #Dehum).Dehumidifier_SetDehumidifierMode("dehumidifying")
    } else if (current_humidity < 50) {
        (#Lab #Dehum).Switch_Off()
    }
    delay(1 HOUR)
}"}

